// State management helpers
const fs = require('fs');
const stateFile = `/tmp/workflow-state-${$execution.id}.json`;

function readState() {
  if (fs.existsSync(stateFile)) {
    return JSON.parse(fs.readFileSync(stateFile, 'utf8'));
  }
  return {};
}

function writeState(state) {
  fs.writeFileSync(stateFile, JSON.stringify(state, null, 2));
}

const body = $input.first().json.body;
const project = (body.project || '').trim().toLowerCase().replace(/\s+/g, '-');
const action = body.action || 'review';
if (!project) throw new Error('project required');
if (!['review', 'decide', 'gate'].includes(action)) throw new Error('invalid action');

const wp = `/home/node/workspace/${project}`;
const reviewNum = 1;

// Create initial state
const state = {
  project,
  action,
  decision: body.decision || '',
  gateDecision: body.gate_decision || '',
  revisions: body.revisions || '',
  reviewNum,
  wp,
  prdHandoff: `${wp}/handoffs/003-prd-refined.md`,
  councilHandoff: `${wp}/handoffs/004-council-review.md`,
  prdDir: `${wp}/tasks`,
  promptsDir: '/home/node/prompts',
  skillsDir: '/home/node/skills'
};

writeState(state);

// Return action in json for IF node routing
return [{ json: { executionId: $execution.id, project, action } }];

