// State management helpers
const fs = require('fs');
const stateFile = `/tmp/workflow-state-${$execution.id}.json`;

function readState() {
  if (fs.existsSync(stateFile)) {
    return JSON.parse(fs.readFileSync(stateFile, 'utf8'));
  }
  return {};
}

function writeState(state) {
  fs.writeFileSync(stateFile, JSON.stringify(state, null, 2));
}

const state = readState();
const prd = state.prd;
const e = [];

const fm = prd.match(/^---\n([\s\S]*?)\n---/);
if (!fm) e.push('Missing frontmatter');
else {
  const f = fm[1];
  if (!/phase:\s*prd-synthesis/.test(f)) e.push('phase must be prd-synthesis');
  if (!/version:\s*v\d+/.test(f)) e.push('version missing');
}

const secs = [
  [/#{1,3}\s+(?:\d+\.\s+)?Executive Summary/i, 'Executive Summary'],
  [/#{1,3}\s+(?:\d+\.\s+)?Functional Requirements/i, 'Functional Requirements'],
  [/#{1,3}\s+(?:\d+\.\s+)?Non-Functional Requirements/i, 'Non-Functional Requirements'],
  [/#{1,3}\s+(?:\d+\.\s+)?User Stories/i, 'User Stories'],
  [/#{1,3}\s+(?:\d+\.\s+)?Architecture/i, 'Architecture'],
  [/#{1,3}\s+(?:\d+\.\s+)?Risk/i, 'Risk Assessment'],
  [/#{1,3}\s+(?:\d+\.\s+)?MVP/i, 'MVP']
];

for (const [p, n] of secs) if (!p.test(prd)) e.push(`Missing ${n}`);

const frCt = (prd.match(/\*\*FR-\d+:/g) || []).length;
if (frCt < 3) e.push(`< 3 FRs (${frCt})`);

const nfr = prd.match(/#{1,3}\s+(?:\d+\.\s+)?Non-Functional[\s\S]*?(?=\n#{1,3}\s)/i)?.[0] || '';
if (nfr && !/\d+\s*(?:ms|s|%|concurrent|users|GB|MB)/.test(nfr)) e.push('NFR lacks numeric targets');

const usCt = (prd.match(/\*\*US-\d+:/g) || []).length;
if (usCt < 3) e.push(`< 3 user stories (${usCt})`);

const risk = prd.match(/#{1,3}\s+(?:\d+\.\s+)?Risk[\s\S]*?(?=\n#{1,3}\s|$)/i)?.[0] || '';
const riskRows = (risk.match(/\|[^|\n]+\|[^|\n]+\|[^|\n]+\|[^|\n]+\|/g) || []).filter(r => !r.includes('---') && !/likelihood/i.test(r));
if (riskRows.length < 2) e.push(`< 2 risks (${riskRows.length})`);

const valid = e.length === 0;

// Write state
state.valid = valid;
state.errors = e;
writeState(state);

// Return valid/errors in json for IF node routing
return [{ json: { valid, errors: e } }];

