// State management helpers
const fs = require('fs');
const stateFile = `/tmp/workflow-state-${$execution.id}.json`;

function readState() {
  if (fs.existsSync(stateFile)) {
    return JSON.parse(fs.readFileSync(stateFile, 'utf8'));
  }
  return {};
}

function writeState(state) {
  fs.writeFileSync(stateFile, JSON.stringify(state, null, 2));
}

const state = readState();
const decision = state.decision;
const revisions = state.revisions;

// Update PRD version if accepted
let newVersion = 'v1';
if (decision === 'ACCEPTED') {
  const prd = fs.readFileSync(state.prdHandoff, 'utf8');
  const vMatch = prd.match(/version:\s*v(\d+)/);
  const currentVer = vMatch ? parseInt(vMatch[1]) : 0;
  newVersion = `v${currentVer + 1}`;

  // Update PRD frontmatter
  const updatedPrd = prd.replace(/version:\s*v\d+/, `version: ${newVersion}`);
  fs.writeFileSync(state.prdHandoff, updatedPrd, 'utf8');
}

state.newPrdVersion = newVersion;
state.decisionRecorded = true;
writeState(state);

return [{
  json: {
    decision,
    new_prd_version: newVersion,
    project: state.project
  }
}];

