  return {};
}

function writeState(state) {
  fs.writeFileSync(stateFile, JSON.stringify(state, null, 2));
}

const state = readState();
const gateDecision = state.gateDecision;

if (gateDecision === 'PROCEED') {
  // Ready for Phase 5
  return [{
    json: {
      gate: 'PROCEED',
      message: 'Ready for Phase 5: Task Generation',
      project: state.project
    }
  }];
} else if (gateDecision === 'RECONVENE') {
  // Prepare for re-review
  const nextReviewNum = state.reviewNum + 1;
  const nextReviewFile = `${state.wp}/handoffs/004-council-review-r${nextReviewNum}.md`;

  return [{
    json: {
      gate: 'RECONVENE',
      next_review_file: nextReviewFile,
      next_review_num: nextReviewNum,
      project: state.project
    }
  }];
}

return [{
  json: {
    error: 'Invalid gate decision',
    project: state.project
  }
}];

